// Timer Callback - Turns the LED on or off depending on the action selected
void IRAM_ATTR timerCallback(TimerHandle_t xTimer) {
  if (targetAction != -1) {
    digitalWrite(ledPin, targetAction ? HIGH : LOW);
    Serial.printf("Timer finished: GPIO %d set to %s\n", ledPin, targetAction ? "HIGH (ON)" : "LOW (OFF)");
  }
  targetAction = -1;
  timerStartTick = 0;
  totalDurationTicks = 0;
}

void setup() {
  Serial.begin(115200);
  delay(1000);

  // Define ledPin as an OUTPUT and initialize it off (LOW)
  pinMode(ledPin, OUTPUT);
  digitalWrite(ledPin, LOW);

  // Create a timer and assign the timerCallback function
  gpioTimer = xTimerCreate("GPIO_Timer", pdMS_TO_TICKS(1000), pdFALSE, 0, timerCallback);

  // Start the Wi-Fi connection
  WiFi.begin(ssid, password);
  Serial.print("Connecting to Wi-Fi");
  while (WiFi.status() != WL_CONNECTED) {
    delay(500);
    Serial.print(".");
  }
  Serial.println("\nWi-Fi Connected!");
  // Print the ESP32 IP Address
  Serial.print("Access ESP32 IP Address: http://");
  Serial.println(WiFi.localIP());

  // Root URL handler
  server.on("/", HTTP_GET, [](AsyncWebServerRequest *request) {
    request->send_P(200, "text/html", index_html);
  });

  // Instant LED control
  server.on("/control", HTTP_GET, [](AsyncWebServerRequest *request) {
    if (request->hasParam("state")) {
      int state = request->getParam("state")->value().toInt();
      digitalWrite(ledPin, state ? HIGH : LOW);
      Serial.printf("LED set to %s\n", state ? "ON" : "OFF");
    }
    request->send(200, "text/plain", "OK");
  });

  // Get current LED state
  server.on("/led-state", HTTP_GET, [](AsyncWebServerRequest *request) {
    int state = digitalRead(ledPin);
    request->send(200, "application/json", "{\"state\":" + String(state) + "}");
  });

  // Set the timer duration to perform the action selected
  server.on("/set-timer", HTTP_POST, [](AsyncWebServerRequest *request) {
    if (request->hasParam("action", true) && request->hasParam("duration", true) && request->hasParam("unit", true)) {

      targetAction = request->getParam("action", true)->value().toInt();
      int dur = request->getParam("duration", true)->value().toInt();
      String unit = request->getParam("unit", true)->value();

      uint64_t durationSeconds = 0;
      if (unit == "s")      durationSeconds = (uint64_t)dur;
      else if (unit == "m") durationSeconds = (uint64_t)dur * 60ULL;
      else if (unit == "h") durationSeconds = (uint64_t)dur * 3600ULL;

      if (durationSeconds > 0) {
        if (xTimerIsTimerActive(gpioTimer)) xTimerStop(gpioTimer, 0);

        uint64_t tempTicks = durationSeconds * (uint64_t)configTICK_RATE_HZ;
        TickType_t timerTicks = (tempTicks > 0xFFFFFFFFULL) ? 0xFFFFFFFFULL : (TickType_t)tempTicks;

        timerStartTick = xTaskGetTickCount();
        totalDurationTicks = tempTicks;

        xTimerChangePeriod(gpioTimer, timerTicks, 0);
        xTimerStart(gpioTimer, 0);

        Serial.printf("Timer scheduled: GPIO %d will be set to %s in %llu seconds\n", ledPin,
                      targetAction ? "ON" : "OFF", durationSeconds);
      }
    }
    request->redirect("/");
  });

  // Cancel Timer
  server.on("/cancel-timer", HTTP_POST, [](AsyncWebServerRequest *request) {
    // Stop the active timer
    if (xTimerIsTimerActive(gpioTimer)) {
      xTimerStop(gpioTimer, 0);
      Serial.println("Timer cancelled");
    }
    targetAction = -1;
    timerStartTick = 0; 
    totalDurationTicks = 0;
    request->send(200, "text/plain", "OK");
  });

  // Timer Status - Returns the remaining time in seconds
  server.on("/timer-status", HTTP_GET, [](AsyncWebServerRequest *request) {
    if (targetAction != -1 && xTimerIsTimerActive(gpioTimer) && totalDurationTicks > 0) {
      // Calculate how many seconds are left for the timer to end
      TickType_t now = xTaskGetTickCount();
      uint64_t elapsedTicks = 0;

      if (now >= timerStartTick) {
        elapsedTicks = now - timerStartTick;
      } else {
        elapsedTicks = (0xFFFFFFFFULL - timerStartTick) + now + 1;
      }

      uint64_t remainingTicks = (totalDurationTicks > elapsedTicks) ? totalDurationTicks - elapsedTicks : 0;
      uint64_t remainingSeconds = remainingTicks / (uint64_t)configTICK_RATE_HZ;

      // Return the amount of seconds left and action that will execute when the timer ends
      String json = "{\"status\":\"Setting GPIO "+ String(ledPin) +" to " + 
                    String(targetAction ? "ON" : "OFF") + "\",";
      json += "\"active\":true,";
      json += "\"remaining_seconds\":" + String((unsigned long)remainingSeconds) + "}";
      request->send(200, "application/json", json);
    } else {
      request->send(200, "application/json", "{\"status\":\"No active timers\",\"active\":false,\"remaining_seconds\":0}");
    }
  });

  server.begin();
  Serial.println("ESP32 Web Server Timer Schedule is Ready!");
}

void loop() {
  vTaskDelay(pdMS_TO_TICKS(100));
}
```

## Cómo funciona el código

A grandes rasgos, el sketch hace lo siguiente:

1. **Conecta el ESP32 a tu red Wi-Fi** usando las credenciales que pongas en `ssid` y `password`.
2. **Levanta un servidor web asincrónico** en el puerto 80 con la librería ESPAsyncWebServer.
3. **Define las rutas HTTP** del servidor:
   - `/` → devuelve la página HTML con el formulario y los botones.
   - `/control?state=1` / `/control?state=0` → enciende o apaga el LED de inmediato.
   - `/led-state` → devuelve el estado actual del LED en JSON.
   - `/set-timer` → recibe el formulario y crea un temporizador FreeRTOS con la duración seleccionada.
   - `/timer-status` → devuelve el estado del temporizador (activo, segundos restantes).
   - `/cancel-timer` → cancela el temporizador en curso.
4. **Usa timers de FreeRTOS** (`xTimerCreate`, `xTimerStart`, `xTimerStop`) para programar la acción sin bloquear el loop principal.
5. **La página web** consulta el estado cada 10 segundos con `fetch()` y actualiza la cuenta regresiva en tiempo real con `setInterval()`.

## Subir y probar

1. **Conecta** tu ESP32 al PC con el cable USB.
2. **Configura** el board y el puerto en el Arduino IDE (Tools > Board > ESP32 Dev Module, y selecciona el puerto correcto).
3. **Sube el código** con el botón Upload.
4. **Abre el Serial Monitor** a 115200 baudios para ver la dirección IP que el ESP32 obtuvo del router.
5. **Escribe esa IP** en tu navegador (PC o teléfono en la misma red Wi-Fi) y deberías ver la página de control.

Prueba a definir un temporizador de 30 segundos para ENCENDER el LED. El estado y el tiempo restante deberían actualizarse automáticamente.

## Conclusión

Con menos de 300 líneas de código tienes un sistema completo de control remoto con temporizador para cualquier carga conectada al ESP32 (no solo un LED — puedes adaptar el código para controlar un relé, una bomba, una luz, etc.). El uso de `ESPAsyncWebServer` + timers de FreeRTOS hace que la solución sea robusta y no bloqueante, ideal para proyectos IoT que necesitan ejecutar acciones programadas sin depender de un servidor externo.

## Introducción

En este proyecto vamos a armar un mini termómetro WiFi que muestra la temperatura actual de tu ciudad en un display **TM1637 de 4 dígitos y 7 segmentos**, sin necesidad de ningún sensor físico. La gracia es que la temperatura la pedimos vía HTTP a la **WeatherAPI**, así que la placa ESP32 solo necesita estar conectada a tu red WiFi.

El display alterna automáticamente entre la lectura en grados Celsius y en Fahrenheit cada 5 segundos, y la consulta a la API se refresca cada 1 hora para no quemar el cuota gratuita.

> **Probado en:** ESP32 DevKit (cualquier modelo con WiFi sirve) + módulo TM1637 4 dígitos tipo reloj.

## Lo que vas a aprender

- Configurar el módulo TM1637 con el ESP32 usando solo 2 pines digitales.
- Hacer peticiones HTTP GET desde el ESP32 a una API externa.
- Parsear JSON con ArduinoJson para extraer campos puntuales.
- Crear símbolos personalizados (°C, °F) en un display de 7 segmentos.

## Prerrequisitos

Antes de partir, asegúrate de tener:

1. **Arduino IDE** instalado con el soporte para placas ESP32 agregado (vía Board Manager).
2. Una **cuenta gratuita en WeatherAPI** (weatherapi.com) para obtener tu API key. El plan free es más que suficiente.
3. Tu **SSID y contraseña WiFi** a mano.

## Materiales

- ESP32 DevKit (cualquier variante con WiFi).
- Módulo display TM1637 de 4 dígitos y 7 segmentos.
- Cables tipo dupont macho-macho para las conexiones.
- Cable USB para alimentar y programar el ESP32.

**Costo aproximado:** ~CLP $13.880 (aproximado, según componentes que tengas disponibles).

## Conociendo el TM1637

El TM1637 es un módulo que combina **4 dígitos de 7 segmentos** en una sola placa, controlados por el chip driver TM1637. Los 4 dígitos están separados por dos puntos (`:`) entre el segundo y el tercero, lo que lo hace ideal para relojes y, en nuestro caso, para mostrar valores numéricos con símbolos.

Una gran ventaja: el módulo se controla con apenas **2 pines digitales** (CLK y DIO) más alimentación, así que no acapara los GPIOs del ESP32.

## Obtener tu API Key de WeatherAPI

1. Entra a [weatherapi.com](https://www.weatherapi.com/) y crea una cuenta gratis.
2. Verifica tu email e inicia sesión.
3. En tu dashboard (weatherapi.com/my/) vas a encontrar tu API key. Aunque diga que el trial expira, la key sigue funcionando libremente en el tier free.
4. Cópiala a un lugar seguro: la vas a necesitar dentro del código.

Para probarla rápido, abre esta URL en tu navegador reemplazando los valores entre llaves:

```
https://api.weatherapi.com/v1/current.json?q={TU_CIUDAD}&key={TU_API_KEY}
```

La API te devuelve un JSON con un montón de datos. Para este proyecto nos interesan dos campos: `current.temp_c` y `current.temp_f`.

## Conexiones físicas

Cablear el TM1637 al ESP32 es directo. Solo 4 cables:

| TM1637 | ESP32          |
|--------|----------------|
| CLK    | GPIO 19        |
| DIO    | GPIO 18        |
| VCC    | VIN (5V) o 3V3 |
| GND    | GND            |

Puedes usar otros GPIOs si los 18 y 19 ya los tienes ocupados; basta con cambiar los `#define` en el código.

## Instalación de librerías

Desde el **Library Manager** de Arduino IDE, instala:

1. **TM1637** (de avishorp): para controlar el display. Es vieja pero anda perfecto.
2. **ArduinoJson** (de bblanchon): para parsear el JSON que devuelve la WeatherAPI.

Los headers nativos `WiFi.h` y `HTTPClient.h` ya vienen incluidos con el core de ESP32.

## El código

Antes de subir, reemplaza tres cosas en el código:

- `REPLACE_WITH_YOUR_SSID` → nombre de tu red WiFi.
- `REPLACE_WITH_YOUR_PASSWORD` → contraseña de la red.
- `REPLACE_WITH_YOUR_WeatherAPI_API_Key` → tu API key.
- `Oporto` → cambia por tu ciudad (Santiago, Valparaíso, Concepción, etc.).

```cpp
#include <WiFi.h>
#include <HTTPClient.h>
#include <ArduinoJson.h>
#include <TM1637Display.h>

// Credenciales WiFi
const char* ssid = "REPLACE_WITH_YOUR_SSID";
const char* password = "REPLACE_WITH_YOUR_PASSWORD";

const char* api_key = "REPLACE_WITH_YOUR_WeatherAPI_API_Key";
const char* location = "Santiago";

String url = "https://api.weatherapi.com/v1/current.json?q=" + String(location) + "&key=" + String(api_key);

// Pines del TM1637
#define CLK 19
#define DIO 18

TM1637Display display(CLK, DIO);

// Símbolo °C
const uint8_t Celsius[] = {
  SEG_A | SEG_B | SEG_F | SEG_G,  // Círculo (grado)
  SEG_A | SEG_D | SEG_E | SEG_F   // C
};

// Símbolo °F
const uint8_t Fahrenheit[] = {
  SEG_A | SEG_B | SEG_F | SEG_G,  // Círculo (grado)
  SEG_F | SEG_E | SEG_A | SEG_G   // F
};

float currentTempC = 9999;
float currentTempF = 9999;
unsigned long lastFetchTime = 0;
const unsigned long fetchInterval = 3600000UL;  // 1 hora

void initWiFi() {
  WiFi.begin(ssid, password);
  while (WiFi.status() != WL_CONNECTED) {
    delay(1000);
    Serial.println("Conectando a WiFi..");
  }
  Serial.println("Conexión exitosa");
  Serial.print("IP: ");
  Serial.println(WiFi.localIP());
}

bool updateTemperatures() {
  HTTPClient http;
  http.begin(url);
  int httpCode = http.GET();

  if (httpCode == HTTP_CODE_OK) {
    String payload = http.getString();
    Serial.print(payload);

    StaticJsonDocument<1024> doc;
    DeserializationError error = deserializeJson(doc, payload);
    if (error) {
      Serial.print("Falló parseo JSON: ");
      Serial.println(error.c_str());
      http.end();
      return false;
    }

    currentTempC = doc["current"]["temp_c"];
    currentTempF = doc["current"]["temp_f"];
    http.end();
    return true;
  } else {
    Serial.print("Error en la petición: ");
    Serial.println(httpCode);
    http.end();
    return false;
  }
}

void setup() {
  Serial.begin(115200);
  delay(1000);
  initWiFi();
  display.setBrightness(7);

  if (updateTemperatures()) {
    lastFetchTime = millis();
  }
}

void loop() {
  if (millis() - lastFetchTime >= fetchInterval) {
    if (updateTemperatures()) {
      lastFetchTime = millis();
    } else {
      Serial.println("Falló el refresco, mantengo valores anteriores.");
    }
  }

  // Mostrar Celsius
  int roundedTempC = round(currentTempC);
  display.showNumberDec(roundedTempC, false, 2, 0);
  display.setSegments(Celsius, 2, 2);
  delay(5000);

  // Mostrar Fahrenheit
  int roundedTempF = round(currentTempF);
  display.showNumberDec(roundedTempF, false, 2, 0);
  display.setSegments(Fahrenheit, 2, 2);
  delay(5000);
}
```

## Cómo funciona el código

### Conexión WiFi
La función `initWiFi()` deja al ESP32 conectado a tu red WiFi. Si no logra conectarse, queda imprimiendo el aviso hasta que enganche.

### Petición a WeatherAPI
`updateTemperatures()` arma la URL, hace el GET, valida que el código de respuesta sea 200 y parsea el JSON con ArduinoJson. Si todo va bien, guarda `temp_c` y `temp_f` en variables globales.

### Refresco cada hora
Usamos `millis()` con un intervalo de 3.600.000 ms (1 hora). Sin esto, la WeatherAPI nos cortaría el servicio rápido en su plan free por demasiadas requests.

### Símbolos °C y °F
Los arrays `Celsius` y `Fahrenheit` definen, segmento por segmento, los caracteres especiales. El círculo del grado se forma encendiendo los segmentos A, B, F, G del primer dígito.

### Loop alternado
Cada 5 segundos cambiamos entre los dos modos: primero muestra `roundedTempC + °C`, luego `roundedTempF + °F`, y vuelve a empezar.

## Probando el proyecto

Una vez subido el código, abre el **Monitor Serial a 115200 baudios**. Deberías ver:

1. La conexión al WiFi y la IP asignada al ESP32.
2. El payload completo del JSON que devuelve WeatherAPI.
3. La temperatura actual de tu ciudad alternándose en el display TM1637.

Si el display muestra `9999`, significa que la primera petición a la API falló — revisa la API key, el nombre de la ciudad y que tengas señal WiFi estable.

## Ideas para extender

- Agregar un sensor DHT22 local y comparar la temperatura medida vs la pronosticada.
- Mostrar humedad o velocidad del viento alternando con la temperatura.
- Encender un LED RGB según el rango de temperatura (azul si <10°C, verde 10-25°C, rojo >25°C).
- Subir el dato a un dashboard con MQTT o Home Assistant.

